///
/// let lang = get_language("python").unwrap();
/// // Use the Language with a tree-sitter Parser
/// let mut parser = tree_sitter::Parser::new();
/// parser.set_language(&lang).unwrap();
/// let tree = parser.parse("x = 1", None).unwrap();
